+    D3D9Range() { clear(); }
+
+    D3D9Range(uint32_t min, uint32_t max)
+      : min(min), max(max) { }
+
+    bool degenerate() { return min == max; }
+
+    bool overlap(D3D9Range range) {
+      if (degenerate()) {
+        *this = range;
+        return false;
