+              m_module.constvec4f32(1.0f, 1.0f, 1.0f, 1.0f));
+
             break;
+          }

           case D3DTOP_MULTIPLYADD:
             dst = m_module.opFFma(m_vec4Type, arg[1], arg[2], arg[0]);

